        if not isinstance(config, dict):
            raise ValueError("Remote config must be a JSON object.")

        dependencies = config.get("dependencies", [])

        if not isinstance(dependencies, list):
            raise ValueError("'dependencies' must be a list.")

        if len(dependencies) > 50:
            raise ValueError("Too many dependencies specified (max 50).")

        validated_deps = []
        for dep in dependencies:
            if not isinstance(dep, str):
                raise ValueError(f"Each dependency must be a string, got: {type(dep)}")

            # Validate against allowlist
            pkg_name = validate_package_name(dep)

            # Enforce version pinning from our allowlist
