    cmd = [
        sys.executable,
        "-m",
        "pip",
        "install",
        "--no-cache-dir",       # Don't use cached packages
        "--require-hashes" if hash_args else "",  # Require hashes if available
        "--no-deps",            # Don't auto-install transitive deps
    ]

    # Remove empty strings
